/**
 * Dependency Graph Implementation
 * 
 * Builds a Directed Acyclic Graph (DAG) from features.json
 * to determine task execution order and parallelization opportunities.
 */

import type { Feature, FeaturesFile } from '../types';

/**
 * Represents a node in the dependency graph
 */
interface GraphNode {
  id: string;
  feature: Feature;
  dependencies: Set<string>;  // Tasks this depends on
  dependents: Set<string>;    // Tasks that depend on this
}

/**
 * Dependency Graph for task scheduling
 */
export class DependencyGraph {
  private nodes: Map<string, GraphNode> = new Map();

  /**
   * Build graph from features file
   */
  static fromFeatures(featuresFile: FeaturesFile): DependencyGraph {
    const graph = new DependencyGraph();

    // First pass: add all nodes
    for (const feature of featuresFile.features) {
      graph.addNode(feature);
    }

    // Second pass: add edges
    for (const feature of featuresFile.features) {
      if (feature.blockedBy) {
        const blockers = Array.isArray(feature.blockedBy) 
          ? feature.blockedBy 
          : [feature.blockedBy];

        for (const blocker of blockers) {
          graph.addEdge(blocker, feature.id);
        }
      }
    }

    return graph;
  }

  /**
   * Add a node to the graph
   */
  addNode(feature: Feature): void {
    if (this.nodes.has(feature.id)) {
      throw new Error(`Duplicate feature ID: ${feature.id}`);
    }

    this.nodes.set(feature.id, {
      id: feature.id,
      feature,
      dependencies: new Set(),
      dependents: new Set(),
    });
  }

  /**
   * Add a directed edge (dependency relationship)
   * @param from The task that must complete first (dependency)
   * @param to The task that depends on 'from' (dependent)
   */
  addEdge(from: string, to: string): void {
    const fromNode = this.nodes.get(from);
    const toNode = this.nodes.get(to);

    if (!fromNode) {
      throw new Error(`Unknown dependency: ${from} (referenced by ${to})`);
    }
    if (!toNode) {
      throw new Error(`Unknown task: ${to}`);
    }

    fromNode.dependents.add(to);
    toNode.dependencies.add(from);
  }

  /**
   * Get all nodes in the graph
   */
  getAllNodes(): GraphNode[] {
    return Array.from(this.nodes.values());
  }

  /**
   * Get a specific node by ID
   */
  getNode(id: string): GraphNode | undefined {
    return this.nodes.get(id);
  }

  /**
   * Get direct dependencies of a task
   */
  getDependencies(id: string): string[] {
    const node = this.nodes.get(id);
    return node ? Array.from(node.dependencies) : [];
  }

  /**
   * Get all tasks that depend on this task
   */
  getDependents(id: string): string[] {
    const node = this.nodes.get(id);
    return node ? Array.from(node.dependents) : [];
  }

  /**
   * Get tasks with no dependencies (root tasks)
   */
  getRootTasks(): Feature[] {
    return this.getAllNodes()
      .filter(node => node.dependencies.size === 0)
      .map(node => node.feature);
  }

  /**
   * Get tasks that are ready to execute
   * (all dependencies are completed/passed)
   */
  getReadyTasks(): Feature[] {
    return this.getAllNodes()
      .filter(node => {
        // Skip already completed tasks
        if (node.feature.passes) return false;

        // Check all dependencies are completed
        for (const depId of node.dependencies) {
          const depNode = this.nodes.get(depId);
          if (!depNode || !depNode.feature.passes) {
            return false;
          }
        }

        return true;
      })
      .map(node => node.feature);
  }

  /**
   * Perform topological sort
   * Returns tasks in valid execution order
   */
  topologicalSort(): Feature[] {
    const result: Feature[] = [];
    const visited = new Set<string>();
    const temp = new Set<string>(); // For cycle detection

    const visit = (id: string): void => {
      if (temp.has(id)) {
        throw new Error(`Circular dependency detected involving: ${id}`);
      }
      if (visited.has(id)) return;

      temp.add(id);

      const node = this.nodes.get(id)!;
      for (const depId of node.dependencies) {
        visit(depId);
      }

      temp.delete(id);
      visited.add(id);
      result.push(node.feature);
    };

    for (const node of this.nodes.values()) {
      if (!visited.has(node.id)) {
        visit(node.id);
      }
    }

    return result;
  }

  /**
   * Validate the graph
   * - Check for cycles
   * - Check for missing dependencies
   */
  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    // Check for cycles by attempting topological sort
    try {
      this.topologicalSort();
    } catch (e) {
      errors.push((e as Error).message);
    }

    // Check for missing dependencies
    for (const node of this.nodes.values()) {
      for (const depId of node.dependencies) {
        if (!this.nodes.has(depId)) {
          errors.push(`Missing dependency: ${depId} (required by ${node.id})`);
        }
      }
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }

  /**
   * Get graph statistics
   */
  getStats(): {
    totalNodes: number;
    totalEdges: number;
    maxDepth: number;
    parallelizableGroups: number;
  } {
    let totalEdges = 0;
    for (const node of this.nodes.values()) {
      totalEdges += node.dependencies.size;
    }

    // Calculate max depth (longest path)
    const depths = new Map<string, number>();
    const sorted = this.topologicalSort();

    for (const feature of sorted) {
      const node = this.nodes.get(feature.id)!;
      let maxDepth = 0;
      for (const depId of node.dependencies) {
        maxDepth = Math.max(maxDepth, (depths.get(depId) || 0) + 1);
      }
      depths.set(feature.id, maxDepth);
    }

    const maxDepth = Math.max(0, ...depths.values());

    // Count parallelizable groups (tasks at same depth)
    const depthGroups = new Map<number, number>();
    for (const depth of depths.values()) {
      depthGroups.set(depth, (depthGroups.get(depth) || 0) + 1);
    }

    return {
      totalNodes: this.nodes.size,
      totalEdges,
      maxDepth,
      parallelizableGroups: depthGroups.size,
    };
  }
}
