/**
 * Critical Path Analysis
 * 
 * Calculates the critical path through the dependency graph
 * to identify which tasks are most important for minimizing
 * total completion time.
 */

import type { Feature } from '../types';
import { DependencyGraph } from './DependencyGraph';

/**
 * Task with critical path information
 */
export interface CriticalPathTask {
  feature: Feature;
  earliestStart: number;   // Earliest possible start time
  latestStart: number;     // Latest start without delaying project
  slack: number;           // latestStart - earliestStart
  isCritical: boolean;     // On the critical path (slack === 0)
  depth: number;           // Distance from root
}

/**
 * Result of critical path analysis
 */
export interface CriticalPathResult {
  tasks: CriticalPathTask[];
  criticalPath: Feature[];     // Tasks on the critical path
  minimumDuration: number;     // Minimum time to complete all tasks
  parallelizationFactor: number; // How much parallelization is possible
}

/**
 * Calculate critical path and task priorities
 */
export function analyzeCriticalPath(
  graph: DependencyGraph,
  estimatedDurations?: Map<string, number>
): CriticalPathResult {
  // Default duration of 1 unit per task if not provided
  const getDuration = (id: string): number => {
    return estimatedDurations?.get(id) ?? 1;
  };

  const sorted = graph.topologicalSort();
  const taskInfo = new Map<string, CriticalPathTask>();

  // Forward pass: calculate earliest start times
  for (const feature of sorted) {
    const deps = graph.getDependencies(feature.id);
    let earliestStart = 0;
    let depth = 0;

    for (const depId of deps) {
      const depInfo = taskInfo.get(depId)!;
      const depFinish = depInfo.earliestStart + getDuration(depId);
      earliestStart = Math.max(earliestStart, depFinish);
      depth = Math.max(depth, depInfo.depth + 1);
    }

    taskInfo.set(feature.id, {
      feature,
      earliestStart,
      latestStart: 0, // Will be calculated in backward pass
      slack: 0,
      isCritical: false,
      depth,
    });
  }

  // Calculate project completion time
  let projectDuration = 0;
  for (const feature of sorted) {
    const info = taskInfo.get(feature.id)!;
    projectDuration = Math.max(
      projectDuration,
      info.earliestStart + getDuration(feature.id)
    );
  }

  // Backward pass: calculate latest start times
  const reverseSorted = [...sorted].reverse();

  for (const feature of reverseSorted) {
    const info = taskInfo.get(feature.id)!;
    const dependents = graph.getDependents(feature.id);

    if (dependents.length === 0) {
      // No dependents - latest start is project end minus duration
      info.latestStart = projectDuration - getDuration(feature.id);
    } else {
      // Latest start is minimum of dependents' latest starts minus this duration
      let latestStart = Infinity;
      for (const depId of dependents) {
        const depInfo = taskInfo.get(depId)!;
        latestStart = Math.min(latestStart, depInfo.latestStart);
      }
      info.latestStart = latestStart - getDuration(feature.id);
    }

    // Calculate slack and critical status
    info.slack = info.latestStart - info.earliestStart;
    info.isCritical = info.slack === 0;
  }

  // Extract critical path (tasks with zero slack, in order)
  const criticalPath = sorted.filter(f => taskInfo.get(f.id)!.isCritical);

  // Calculate parallelization factor
  // (total work / critical path length)
  const totalWork = sorted.reduce((sum, f) => sum + getDuration(f.id), 0);
  const parallelizationFactor = totalWork / projectDuration;

  return {
    tasks: sorted.map(f => taskInfo.get(f.id)!),
    criticalPath,
    minimumDuration: projectDuration,
    parallelizationFactor,
  };
}

/**
 * Get priority score for a task
 * Higher score = should be scheduled first
 */
export function getTaskPriority(task: CriticalPathTask): number {
  let priority = 0;

  // Critical path tasks get highest priority
  if (task.isCritical) {
    priority += 1000;
  }

  // Lower slack = higher priority
  priority += Math.max(0, 100 - task.slack * 10);

  // Earlier depth = higher priority (unblock more tasks)
  priority += Math.max(0, 50 - task.depth * 5);

  return priority;
}

/**
 * Format critical path analysis for display
 */
export function formatCriticalPathReport(result: CriticalPathResult): string {
  const lines: string[] = [];

  lines.push('=== Critical Path Analysis ===\n');
  lines.push(`Minimum Duration: ${result.minimumDuration} units`);
  lines.push(`Parallelization Factor: ${result.parallelizationFactor.toFixed(2)}x`);
  lines.push(`Critical Path Length: ${result.criticalPath.length} tasks\n`);

  lines.push('Critical Path:');
  for (const feature of result.criticalPath) {
    lines.push(`  -> ${feature.id}: ${feature.title}`);
  }
  lines.push('');

  lines.push('All Tasks:');
  lines.push('ID\t\t\tEarliest\tLatest\t\tSlack\tCritical');
  lines.push('-'.repeat(70));

  for (const task of result.tasks) {
    const critical = task.isCritical ? '*' : '';
    lines.push(
      `${task.feature.id}\t\t${task.earliestStart}\t\t${task.latestStart}\t\t${task.slack}\t${critical}`
    );
  }

  return lines.join('\n');
}
