/**
 * Task Scheduler
 * 
 * Manages the ready queue and dispatches tasks to agents
 * based on priority and resource availability.
 */

import type { Feature, Task, TaskStatus, OrchestratorConfig } from '../types';
import { DependencyGraph } from '../graph/DependencyGraph';
import { analyzeCriticalPath, getTaskPriority, type CriticalPathTask } from '../graph/CriticalPath';
import { PriorityQueue } from './PriorityQueue';

/**
 * Event types emitted by the scheduler
 */
export type SchedulerEvent = 
  | { type: 'task-ready'; task: Task }
  | { type: 'task-started'; task: Task; agentId: string }
  | { type: 'task-completed'; task: Task }
  | { type: 'task-failed'; task: Task; error: string }
  | { type: 'all-complete' }
  | { type: 'deadlock'; pendingTasks: Task[] };

/**
 * Listener for scheduler events
 */
export type SchedulerListener = (event: SchedulerEvent) => void;

/**
 * Task Scheduler - manages task execution order
 */
export class TaskScheduler {
  private graph: DependencyGraph;
  private tasks: Map<string, Task>;
  private readyQueue: PriorityQueue<Task>;
  private criticalPathInfo: Map<string, CriticalPathTask>;
  private listeners: Set<SchedulerListener> = new Set();
  private runningCount: number = 0;
  private config: OrchestratorConfig;

  constructor(graph: DependencyGraph, config: OrchestratorConfig) {
    this.graph = graph;
    this.config = config;
    this.tasks = new Map();
    this.criticalPathInfo = new Map();

    // Initialize priority queue with task priority function
    this.readyQueue = new PriorityQueue<Task>((task) => {
      const cpInfo = this.criticalPathInfo.get(task.id);
      return cpInfo ? getTaskPriority(cpInfo) : 0;
    });

    this.initializeTasks();
  }

  /**
   * Initialize tasks from the dependency graph
   */
  private initializeTasks(): void {
    // Analyze critical path
    const cpResult = analyzeCriticalPath(this.graph);
    for (const cpTask of cpResult.tasks) {
      this.criticalPathInfo.set(cpTask.feature.id, cpTask);
    }

    // Create Task objects from Features
    for (const node of this.graph.getAllNodes()) {
      const feature = node.feature;
      const status: TaskStatus = feature.passes ? 'completed' : 'pending';

      const task: Task = {
        ...feature,
        status,
        retryCount: 0,
      };

      this.tasks.set(feature.id, task);
    }

    // Populate initial ready queue
    this.updateReadyQueue();
  }

  /**
   * Update the ready queue based on current state
   */
  private updateReadyQueue(): void {
    for (const task of this.tasks.values()) {
      if (task.status !== 'pending') continue;

      // Check if all dependencies are completed
      const deps = this.graph.getDependencies(task.id);
      const allDepsComplete = deps.every(depId => {
        const depTask = this.tasks.get(depId);
        return depTask?.status === 'completed';
      });

      if (allDepsComplete) {
        task.status = 'ready';
        this.readyQueue.enqueue(task);
        this.emit({ type: 'task-ready', task });
      }
    }
  }

  /**
   * Get the next task to execute
   */
  getNextTask(): Task | undefined {
    if (this.runningCount >= this.config.maxAgents) {
      return undefined;
    }

    return this.readyQueue.dequeue();
  }

  /**
   * Mark a task as started
   */
  startTask(taskId: string, agentId: string): void {
    const task = this.tasks.get(taskId);
    if (!task) throw new Error(`Unknown task: ${taskId}`);
    if (task.status !== 'ready') throw new Error(`Task ${taskId} is not ready`);

    task.status = 'running';
    task.agentId = agentId;
    task.startTime = Date.now();
    this.runningCount++;

    this.emit({ type: 'task-started', task, agentId });
  }

  /**
   * Mark a task as completed
   */
  completeTask(taskId: string): void {
    const task = this.tasks.get(taskId);
    if (!task) throw new Error(`Unknown task: ${taskId}`);
    if (task.status !== 'running') throw new Error(`Task ${taskId} is not running`);

    task.status = 'completed';
    task.endTime = Date.now();
    task.passes = true;
    this.runningCount--;

    this.emit({ type: 'task-completed', task });

    // Check for newly ready tasks
    this.updateReadyQueue();

    // Check if all tasks are complete
    if (this.isComplete()) {
      this.emit({ type: 'all-complete' });
    }
  }

  /**
   * Mark a task as failed
   */
  failTask(taskId: string, error: string): void {
    const task = this.tasks.get(taskId);
    if (!task) throw new Error(`Unknown task: ${taskId}`);
    if (task.status !== 'running') throw new Error(`Task ${taskId} is not running`);

    task.retryCount++;
    this.runningCount--;

    if (task.retryCount < this.config.retryLimit) {
      // Retry: put back in ready queue
      task.status = 'ready';
      task.error = error;
      this.readyQueue.enqueue(task);
    } else {
      // Max retries reached
      task.status = 'failed';
      task.endTime = Date.now();
      task.error = error;
      this.emit({ type: 'task-failed', task, error });

      // Check for deadlock (no progress possible)
      this.checkDeadlock();
    }
  }

  /**
   * Check if all tasks are complete
   */
  isComplete(): boolean {
    for (const task of this.tasks.values()) {
      if (task.status !== 'completed' && task.status !== 'failed') {
        return false;
      }
    }
    return true;
  }

  /**
   * Check for deadlock condition
   */
  private checkDeadlock(): void {
    const pendingTasks = Array.from(this.tasks.values()).filter(
      t => t.status === 'pending' || t.status === 'ready'
    );

    if (pendingTasks.length > 0 && this.runningCount === 0 && this.readyQueue.isEmpty()) {
      // No tasks running, none ready, but some pending
      // This means a dependency chain is blocked by a failed task
      this.emit({ type: 'deadlock', pendingTasks });
    }
  }

  /**
   * Get current scheduler statistics
   */
  getStats(): {
    total: number;
    pending: number;
    ready: number;
    running: number;
    completed: number;
    failed: number;
  } {
    const stats = {
      total: 0,
      pending: 0,
      ready: 0,
      running: 0,
      completed: 0,
      failed: 0,
    };

    for (const task of this.tasks.values()) {
      stats.total++;
      stats[task.status]++;
    }

    return stats;
  }

  /**
   * Get a specific task
   */
  getTask(id: string): Task | undefined {
    return this.tasks.get(id);
  }

  /**
   * Get all tasks
   */
  getAllTasks(): Task[] {
    return Array.from(this.tasks.values());
  }

  /**
   * Add an event listener
   */
  on(listener: SchedulerListener): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  /**
   * Emit an event to all listeners
   */
  private emit(event: SchedulerEvent): void {
    for (const listener of this.listeners) {
      try {
        listener(event);
      } catch (e) {
        console.error('Scheduler listener error:', e);
      }
    }
  }

  /**
   * Check if there are tasks available to run
   */
  hasAvailableWork(): boolean {
    return !this.readyQueue.isEmpty() && this.runningCount < this.config.maxAgents;
  }

  /**
   * Get the number of currently running tasks
   */
  getRunningCount(): number {
    return this.runningCount;
  }
}
