/**
 * Priority Queue Implementation
 * 
 * A simple heap-based priority queue for task scheduling.
 * Higher priority items are dequeued first.
 */

/**
 * Priority function type - returns a number (higher = more priority)
 */
export type PriorityFunction<T> = (item: T) => number;

/**
 * Priority Queue using a binary heap
 */
export class PriorityQueue<T> {
  private heap: T[] = [];
  private getPriority: PriorityFunction<T>;

  constructor(getPriority: PriorityFunction<T>) {
    this.getPriority = getPriority;
  }

  /**
   * Add an item to the queue
   */
  enqueue(item: T): void {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  /**
   * Remove and return the highest priority item
   */
  dequeue(): T | undefined {
    if (this.heap.length === 0) return undefined;

    const result = this.heap[0];
    const last = this.heap.pop()!;

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.bubbleDown(0);
    }

    return result;
  }

  /**
   * Look at the highest priority item without removing it
   */
  peek(): T | undefined {
    return this.heap[0];
  }

  /**
   * Check if the queue is empty
   */
  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  /**
   * Get the number of items in the queue
   */
  size(): number {
    return this.heap.length;
  }

  /**
   * Clear all items from the queue
   */
  clear(): void {
    this.heap = [];
  }

  /**
   * Get all items (for debugging/display)
   */
  toArray(): T[] {
    return [...this.heap];
  }

  /**
   * Bubble up an item to its correct position
   */
  private bubbleUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);

      if (this.getPriority(this.heap[index]) <= this.getPriority(this.heap[parentIndex])) {
        break;
      }

      this.swap(index, parentIndex);
      index = parentIndex;
    }
  }

  /**
   * Bubble down an item to its correct position
   */
  private bubbleDown(index: number): void {
    while (true) {
      const leftChild = 2 * index + 1;
      const rightChild = 2 * index + 2;
      let largest = index;

      if (
        leftChild < this.heap.length &&
        this.getPriority(this.heap[leftChild]) > this.getPriority(this.heap[largest])
      ) {
        largest = leftChild;
      }

      if (
        rightChild < this.heap.length &&
        this.getPriority(this.heap[rightChild]) > this.getPriority(this.heap[largest])
      ) {
        largest = rightChild;
      }

      if (largest === index) break;

      this.swap(index, largest);
      index = largest;
    }
  }

  /**
   * Swap two items in the heap
   */
  private swap(i: number, j: number): void {
    [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
  }
}
