/**
 * Parallel Executor
 * 
 * Manages parallel task execution with configurable concurrency limits.
 * Coordinates with TaskScheduler to execute tasks as they become ready.
 */

import type { Task, OrchestratorConfig, ExecutionResult } from '../types';
import { TaskScheduler } from '../scheduler/TaskScheduler';
import { ExecutionTracker } from './ExecutionTracker';

/**
 * Task executor function type
 * Takes a task and returns a promise that resolves when execution is complete
 */
export type TaskExecutor = (task: Task) => Promise<ExecutionResult>;

/**
 * Execution event types
 */
export type ExecutionEvent =
  | { type: 'execution-started'; totalTasks: number }
  | { type: 'task-dispatched'; task: Task; agentId: string }
  | { type: 'task-success'; task: Task; result: ExecutionResult }
  | { type: 'task-failure'; task: Task; result: ExecutionResult }
  | { type: 'execution-complete'; stats: ExecutionStats }
  | { type: 'execution-error'; error: Error };

/**
 * Execution statistics
 */
export interface ExecutionStats {
  totalTasks: number;
  completedTasks: number;
  failedTasks: number;
  totalDuration: number;
  avgTaskDuration: number;
  parallelEfficiency: number;
}

/**
 * Listener for execution events
 */
export type ExecutionListener = (event: ExecutionEvent) => void;

/**
 * Parallel Executor - runs tasks concurrently
 */
export class ParallelExecutor {
  private scheduler: TaskScheduler;
  private config: OrchestratorConfig;
  private tracker: ExecutionTracker;
  private executor: TaskExecutor;
  private listeners: Set<ExecutionListener> = new Set();
  private agentCounter: number = 0;
  private isRunning: boolean = false;
  private executionPromise: Promise<ExecutionStats> | null = null;

  constructor(
    scheduler: TaskScheduler,
    config: OrchestratorConfig,
    executor: TaskExecutor
  ) {
    this.scheduler = scheduler;
    this.config = config;
    this.tracker = new ExecutionTracker();
    this.executor = executor;

    // Listen to scheduler events
    this.scheduler.on((event) => {
      if (event.type === 'task-ready') {
        this.tryDispatchTasks();
      }
    });
  }

  /**
   * Start parallel execution
   * Returns a promise that resolves when all tasks are complete
   */
  async start(): Promise<ExecutionStats> {
    if (this.isRunning) {
      throw new Error('Execution already in progress');
    }

    this.isRunning = true;
    const startTime = Date.now();
    const stats = this.scheduler.getStats();

    this.emit({ type: 'execution-started', totalTasks: stats.total });

    // Create a promise that resolves when execution is complete
    this.executionPromise = new Promise((resolve, reject) => {
      const checkComplete = () => {
        if (this.scheduler.isComplete()) {
          this.isRunning = false;
          const finalStats = this.calculateFinalStats(startTime);
          this.emit({ type: 'execution-complete', stats: finalStats });
          resolve(finalStats);
          return true;
        }
        return false;
      };

      // Listen for completion or deadlock
      const unsubscribe = this.scheduler.on((event) => {
        if (event.type === 'all-complete') {
          checkComplete();
          unsubscribe();
        } else if (event.type === 'deadlock') {
          this.isRunning = false;
          const error = new Error(
            `Deadlock detected. Pending tasks: ${event.pendingTasks.map(t => t.id).join(', ')}`
          );
          this.emit({ type: 'execution-error', error });
          reject(error);
          unsubscribe();
        }
      });

      // Check if already complete (all tasks already passed)
      if (checkComplete()) {
        unsubscribe();
        return;
      }

      // Start dispatching tasks
      this.tryDispatchTasks();
    });

    return this.executionPromise;
  }

  /**
   * Try to dispatch tasks up to the concurrency limit
   */
  private tryDispatchTasks(): void {
    if (!this.isRunning) return;

    while (this.scheduler.hasAvailableWork()) {
      const task = this.scheduler.getNextTask();
      if (!task) break;

      this.dispatchTask(task);
    }
  }

  /**
   * Dispatch a single task to an agent
   */
  private async dispatchTask(task: Task): Promise<void> {
    const agentId = `agent-${++this.agentCounter}`;

    try {
      this.scheduler.startTask(task.id, agentId);
      this.tracker.startTask(task.id);
      this.emit({ type: 'task-dispatched', task, agentId });

      // Execute the task
      const result = await this.executeWithTimeout(task);

      this.tracker.endTask(task.id, result.success);

      if (result.success) {
        this.scheduler.completeTask(task.id);
        this.emit({ type: 'task-success', task, result });
      } else {
        this.scheduler.failTask(task.id, result.error || 'Unknown error');
        this.emit({ type: 'task-failure', task, result });
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.tracker.endTask(task.id, false);
      this.scheduler.failTask(task.id, errorMessage);
      this.emit({
        type: 'task-failure',
        task,
        result: { taskId: task.id, success: false, duration: 0, error: errorMessage },
      });
    }

    // Try to dispatch more tasks
    this.tryDispatchTasks();
  }

  /**
   * Execute a task with timeout
   */
  private async executeWithTimeout(task: Task): Promise<ExecutionResult> {
    const timeoutPromise = new Promise<ExecutionResult>((_, reject) => {
      setTimeout(() => {
        reject(new Error(`Task ${task.id} timed out after ${this.config.timeoutMs}ms`));
      }, this.config.timeoutMs);
    });

    return Promise.race([this.executor(task), timeoutPromise]);
  }

  /**
   * Calculate final execution statistics
   */
  private calculateFinalStats(startTime: number): ExecutionStats {
    const stats = this.scheduler.getStats();
    const totalDuration = Date.now() - startTime;
    const trackerStats = this.tracker.getStats();

    // Calculate theoretical minimum time (sequential execution)
    const sequentialTime = trackerStats.totalDuration;
    const parallelEfficiency = sequentialTime > 0 ? sequentialTime / totalDuration : 1;

    return {
      totalTasks: stats.total,
      completedTasks: stats.completed,
      failedTasks: stats.failed,
      totalDuration,
      avgTaskDuration: trackerStats.avgDuration,
      parallelEfficiency,
    };
  }

  /**
   * Add an event listener
   */
  on(listener: ExecutionListener): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  /**
   * Emit an event to all listeners
   */
  private emit(event: ExecutionEvent): void {
    for (const listener of this.listeners) {
      try {
        listener(event);
      } catch (e) {
        console.error('Execution listener error:', e);
      }
    }
  }

  /**
   * Check if execution is in progress
   */
  isExecuting(): boolean {
    return this.isRunning;
  }

  /**
   * Get current execution progress
   */
  getProgress(): {
    running: number;
    completed: number;
    failed: number;
    pending: number;
  } {
    const stats = this.scheduler.getStats();
    return {
      running: stats.running,
      completed: stats.completed,
      failed: stats.failed,
      pending: stats.pending + stats.ready,
    };
  }
}
