/**
 * Execution Tracker
 * 
 * Tracks task execution timing and statistics.
 */

/**
 * Individual task timing record
 */
interface TaskTiming {
  taskId: string;
  startTime: number;
  endTime?: number;
  duration?: number;
  success?: boolean;
}

/**
 * Execution Tracker - monitors task execution
 */
export class ExecutionTracker {
  private timings: Map<string, TaskTiming> = new Map();

  /**
   * Record task start
   */
  startTask(taskId: string): void {
    this.timings.set(taskId, {
      taskId,
      startTime: Date.now(),
    });
  }

  /**
   * Record task end
   */
  endTask(taskId: string, success: boolean): void {
    const timing = this.timings.get(taskId);
    if (timing) {
      timing.endTime = Date.now();
      timing.duration = timing.endTime - timing.startTime;
      timing.success = success;
    }
  }

  /**
   * Get timing for a specific task
   */
  getTiming(taskId: string): TaskTiming | undefined {
    return this.timings.get(taskId);
  }

  /**
   * Get all timings
   */
  getAllTimings(): TaskTiming[] {
    return Array.from(this.timings.values());
  }

  /**
   * Get aggregate statistics
   */
  getStats(): {
    totalTasks: number;
    completedTasks: number;
    failedTasks: number;
    totalDuration: number;
    avgDuration: number;
    minDuration: number;
    maxDuration: number;
  } {
    const completed = this.getAllTimings().filter(t => t.duration !== undefined);
    const durations = completed.map(t => t.duration!);
    const successful = completed.filter(t => t.success);
    const failed = completed.filter(t => !t.success);

    return {
      totalTasks: this.timings.size,
      completedTasks: successful.length,
      failedTasks: failed.length,
      totalDuration: durations.reduce((sum, d) => sum + d, 0),
      avgDuration: durations.length > 0 
        ? durations.reduce((sum, d) => sum + d, 0) / durations.length 
        : 0,
      minDuration: durations.length > 0 ? Math.min(...durations) : 0,
      maxDuration: durations.length > 0 ? Math.max(...durations) : 0,
    };
  }

  /**
   * Reset all timings
   */
  reset(): void {
    this.timings.clear();
  }
}
