/**
 * Parallel Feature Runner
 * 
 * Manages parallel feature development using git worktrees.
 * Each feature runs in isolation with its own branch.
 * 
 * Usage:
 *   bun scripts/parallel-runner.ts status           # Show current status
 *   bun scripts/parallel-runner.ts wave 1           # Execute Wave 1
 *   bun scripts/parallel-runner.ts merge F023       # Merge completed feature
 *   bun scripts/parallel-runner.ts cleanup          # Clean up worktrees
 */

import { $ } from 'bun';
import { existsSync } from 'fs';
import { join } from 'path';
import { WAVES, type FeatureConfig } from './parallel-config';

const TREES_DIR = '.trees';
const ROOT_DIR = process.cwd();

// ANSI colors
const colors = {
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  dim: '\x1b[2m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
};

function log(msg: string, color: keyof typeof colors = 'reset') {
  console.log(`${colors[color]}${msg}${colors.reset}`);
}

function logSection(title: string) {
  console.log(`\n${colors.bold}${colors.cyan}=== ${title} ===${colors.reset}\n`);
}

/**
 * Check if a worktree exists
 */
function worktreeExists(featureId: string): boolean {
  return existsSync(join(ROOT_DIR, TREES_DIR, featureId));
}

/**
 * Get list of existing worktrees
 */
async function getWorktrees(): Promise<string[]> {
  const result = await $`git worktree list --porcelain`.text();
  const worktrees: string[] = [];

  for (const line of result.split('\n')) {
    if (line.startsWith('worktree ')) {
      worktrees.push(line.replace('worktree ', ''));
    }
  }

  return worktrees;
}

/**
 * Create a worktree for a feature
 */
async function createWorktree(feature: FeatureConfig): Promise<void> {
  const worktreePath = join(ROOT_DIR, TREES_DIR, feature.id);
  const branchName = `feature/${feature.id.toLowerCase()}`;

  if (worktreeExists(feature.id)) {
    log(`  Worktree already exists: ${feature.id}`, 'yellow');
    return;
  }

  log(`  Creating worktree for ${feature.id}...`, 'blue');

  // Create branch from main if it doesn't exist
  try {
    await $`git branch ${branchName} main 2>/dev/null`.quiet();
  } catch {
    // Branch may already exist, that's ok
  }

  // Create worktree
  await $`git worktree add ${worktreePath} ${branchName}`.quiet();

  log(`  Created: ${worktreePath}`, 'green');
}

/**
 * Remove a worktree
 */
async function removeWorktree(featureId: string): Promise<void> {
  const worktreePath = join(ROOT_DIR, TREES_DIR, featureId);

  if (!worktreeExists(featureId)) {
    log(`  Worktree doesn't exist: ${featureId}`, 'yellow');
    return;
  }

  log(`  Removing worktree: ${featureId}...`, 'blue');
  await $`git worktree remove ${worktreePath} --force`.quiet();
  log(`  Removed: ${worktreePath}`, 'green');
}

/**
 * Show status of all waves and features
 */
async function showStatus(): Promise<void> {
  logSection('Parallel Execution Status');

  const worktrees = await getWorktrees();

  for (const [waveIndex, wave] of WAVES.entries()) {
    log(`\nWave ${waveIndex + 1}:`, 'bold');

    for (const group of wave.groups) {
      const groupStatus = group.features.map(f => {
        const hasWorktree = worktrees.some(w => w.includes(f.id));
        const status = hasWorktree ? '🔄' : '⬚';
        return `${status} ${f.id}`;
      }).join(' → ');

      const riskColor = group.conflictRisk === 'LOW' ? 'green' : 
                       group.conflictRisk === 'MEDIUM' ? 'yellow' : 'red';

      log(`  Group ${group.id} [${group.conflictRisk}]: ${groupStatus}`, riskColor);
    }
  }

  logSection('Legend');
  log('🔄 = Active worktree', 'dim');
  log('⬚  = Not started', 'dim');
}

/**
 * Execute a wave (create worktrees for all groups)
 */
async function executeWave(waveNumber: number): Promise<void> {
  const waveIndex = waveNumber - 1;

  if (waveIndex < 0 || waveIndex >= WAVES.length) {
    log(`Invalid wave number: ${waveNumber}. Valid range: 1-${WAVES.length}`, 'red');
    return;
  }

  const wave = WAVES[waveIndex];
  logSection(`Executing Wave ${waveNumber}`);

  // Create worktrees for all features in this wave
  for (const group of wave.groups) {
    log(`\nGroup ${group.id}:`, 'bold');

    for (const feature of group.features) {
      await createWorktree(feature);
    }
  }

  logSection('Instructions');
  log('For each worktree, open a new terminal and run:', 'dim');
  log('');

  for (const group of wave.groups) {
    for (const feature of group.features) {
      const path = join(TREES_DIR, feature.id);
      log(`  cd ${path} && claude`, 'cyan');
    }
  }

  log('');
  log('Each Claude session will work independently on its feature.', 'dim');
  log('When a feature is complete, run: bun scripts/parallel-runner.ts merge <FEATURE_ID>', 'dim');
}

/**
 * Merge a completed feature back to main
 */
async function mergeFeature(featureId: string): Promise<void> {
  const branchName = `feature/${featureId.toLowerCase()}`;

  logSection(`Merging ${featureId}`);

  // Check if on main branch
  const currentBranch = (await $`git branch --show-current`.text()).trim();
  if (currentBranch !== 'main') {
    log('Switching to main branch...', 'blue');
    await $`git checkout main`.quiet();
  }

  // Pull latest main
  log('Pulling latest main...', 'blue');
  await $`git pull origin main`.quiet();

  // Merge the feature branch
  log(`Merging ${branchName}...`, 'blue');
  try {
    await $`git merge ${branchName} --no-ff -m "Merge ${featureId}: ${featureId}"`;
    log(`Successfully merged ${featureId}!`, 'green');

    // Clean up worktree and branch
    await removeWorktree(featureId);
    await $`git branch -d ${branchName}`.quiet();
    log(`Cleaned up branch: ${branchName}`, 'green');
  } catch (error) {
    log(`Merge conflict! Please resolve manually.`, 'red');
    log(`After resolving, run: git commit && bun scripts/parallel-runner.ts cleanup`, 'yellow');
  }
}

/**
 * Clean up all worktrees
 */
async function cleanup(): Promise<void> {
  logSection('Cleaning Up Worktrees');

  const worktrees = await getWorktrees();
  const treesToRemove = worktrees.filter(w => w.includes(TREES_DIR));

  if (treesToRemove.length === 0) {
    log('No worktrees to clean up.', 'green');
    return;
  }

  for (const worktree of treesToRemove) {
    const featureId = worktree.split('/').pop()!;
    await removeWorktree(featureId);
  }

  // Prune worktree references
  await $`git worktree prune`.quiet();
  log('Pruned worktree references.', 'green');
}

/**
 * Main CLI handler
 */
async function main() {
  const [command, arg] = process.argv.slice(2);

  switch (command) {
    case 'status':
      await showStatus();
      break;

    case 'wave':
      if (!arg) {
        log('Usage: bun scripts/parallel-runner.ts wave <number>', 'red');
        process.exit(1);
      }
      await executeWave(parseInt(arg, 10));
      break;

    case 'merge':
      if (!arg) {
        log('Usage: bun scripts/parallel-runner.ts merge <FEATURE_ID>', 'red');
        process.exit(1);
      }
      await mergeFeature(arg.toUpperCase());
      break;

    case 'cleanup':
      await cleanup();
      break;

    default:
      log('Parallel Feature Runner', 'bold');
      log('');
      log('Commands:', 'cyan');
      log('  status           Show current status of all waves/features');
      log('  wave <number>    Execute a wave (1-4)');
      log('  merge <id>       Merge a completed feature back to main');
      log('  cleanup          Remove all worktrees');
      log('');
      log('Example:', 'dim');
      log('  bun scripts/parallel-runner.ts wave 1');
      log('  bun scripts/parallel-runner.ts merge F023');
  }
}

