interface LockInfo {
  pid: number;
  timestamp: number;
  hostname: string;
}

export class FileLock {
  private lockPath: string;
  private acquired: boolean = false;

  constructor(targetPath: string) {
    this.lockPath = `${targetPath}.lock`;
  }

  /**
   * Acquire lock with exponential backoff
   * @param timeoutMs Maximum time to wait for lock
   * @param retryIntervalMs Initial retry interval
   */
  async acquire(timeoutMs: number = 10000, retryIntervalMs: number = 100): Promise<void>;

  /**
   * Release the lock
   */
  async release(): Promise<void>;

  /**
   * Check if lock file exists and is still valid
   */
  private async isLockValid(): Promise<boolean>;

  /**
   * Check if the process holding the lock is still alive
   */
  private isProcessAlive(pid: number): boolean;
}
