### Implementation Details

#### Atomic Write Pattern

```typescript
async function atomicWrite(filePath: string, content: string): Promise<void> {
  const tempPath = `${filePath}.tmp.${Date.now()}`;

  // Write to temp file
  await Bun.write(tempPath, content);

  // Rename (atomic on POSIX systems)
  const fs = await import('fs/promises');
  await fs.rename(tempPath, filePath);
}
```

#### Lock Acquisition with Backoff

```typescript
async acquire(timeoutMs: number = 10000): Promise<void> {
  const startTime = Date.now();
  let retryInterval = 100;

  while (Date.now() - startTime < timeoutMs) {
    try {
      // Try to create lock file exclusively
      const lockInfo: LockInfo = {
        pid: process.pid,
        timestamp: Date.now(),
        hostname: os.hostname(),
      };

      // Use Bun.write with exclusive flag
      await Bun.write(this.lockPath, JSON.stringify(lockInfo), {
        createPath: false,  // Don't create if exists
      });

      this.acquired = true;
      return;
    } catch {
      // Lock exists, check if stale
      if (await this.isLockStale()) {
        await this.removeStaleLock();
        continue;
      }

      // Wait with exponential backoff
      await Bun.sleep(retryInterval);
      retryInterval = Math.min(retryInterval * 2, 1000);
    }
  }

  throw new Error(`Failed to acquire lock on ${this.lockPath} within ${timeoutMs}ms`);
}
```

#### Stale Lock Detection

```typescript
private async isLockStale(): Promise<boolean> {
  try {
    const content = await Bun.file(this.lockPath).text();
    const lockInfo: LockInfo = JSON.parse(content);

    // Check if process is still alive
    if (!this.isProcessAlive(lockInfo.pid)) {
      return true;
    }

    // Check if lock is too old (e.g., > 5 minutes)
    const maxAge = 5 * 60 * 1000;
    if (Date.now() - lockInfo.timestamp > maxAge) {
      return true;
    }

    return false;
  } catch {
    // Can't read lock file, assume stale
    return true;
  }
}

private isProcessAlive(pid: number): boolean {
  try {
    // Signal 0 checks if process exists without killing it
    process.kill(pid, 0);
    return true;
  } catch {
    return false;
  }
}
```

